const aiResponse = $input.first().json;
const prevData = $('Parse Planning Doc').first().json;

let estimate = null;
if (aiResponse.choices && aiResponse.choices[0]) {
  const content = aiResponse.choices[0].message?.content || '{}';
  try {
    estimate = JSON.parse(content);
  } catch (e) {
    const match = content.match(/\{[\s\S]*\}/);
    if (match) estimate = JSON.parse(match[0]);
  }
}

// Build Notion blocks for planning doc
const planningBlocks = [];
if (prevData.planningDoc && prevData.planningDoc.sections) {
  for (const section of prevData.planningDoc.sections) {
    planningBlocks.push(
      { object: 'block', type: 'heading_3', heading_3: { rich_text: [{ text: { content: String(section.title || '') } }] } },
      { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: String(section.content || '').substring(0, 2000) } }] } }
    );
  }
}

// Build Notion blocks for estimate
const estimateRows = [];
if (estimate && estimate.items) {
  // Header row
  estimateRows.push({
    object: 'block', type: 'table_row',
    table_row: { cells: [[{text:{content:'항목'}}],[{text:{content:'비용'}}],[{text:{content:'비고'}}]] }
  });
  for (const item of estimate.items) {
    estimateRows.push({
      object: 'block', type: 'table_row',
      table_row: { cells: [[{text:{content:item.name}}],[{text:{content:item.price}}],[{text:{content:item.note}}]] }
    });
  }
}

return [{
  json: {
    projectId: prevData.projectId,
    notionPageId: prevData.notionPageId,
    callbackUrl: prevData.callbackUrl,
    planningDoc: prevData.planningDoc,
    estimate,
    planningBlocks: JSON.stringify(planningBlocks),
    estimateRows: JSON.stringify(estimateRows),
    estimateTotal: estimate?.total || ''
  }
}];

